    public class CertificateManager
    {
        public static X509Certificate2 GetCertificateFromStore(StoreLocation location, StoreName name, string thumbprint)
        {
            X509Store store = new X509Store(name, location);
            try
            {
                store.Open(OpenFlags.ReadOnly);
                X509Certificate2Collection certificates = store.Certificates.Find(
                    X509FindType.FindByThumbprint,
                    thumbprint,
                    false);

                if (certificates.Count > 0)
                {
                    return certificates[0];
                }

                throw new Exception($"Certificate with thumbprint {thumbprint} not found");
            }
            finally
            {
                store.Close();
            }
        }

        public static X509Certificate2 CreateSelfSignedCertificate(string subjectName)
        {
            X509Store store = new X509Store(StoreName.My, StoreLocation.CurrentUser);
            store.Open(OpenFlags.ReadWrite);

            X509Certificate2Collection existingCerts = store.Certificates.Find(
                X509FindType.FindBySubjectDistinguishedName,
                $"CN={subjectName}",
                false);

            if (existingCerts.Count > 0)
            {
                store.Close();
                return existingCerts[0];
            }

            store.Close();
            return null;
        }
    }

